const struct letter* const letters = (struct letter*) letterBytes;

const struct letterSet basicFont = {letters, 94};

bool getLetterPixel(struct letterSet letterSet, int letter, int row, int col) {
    letter -= '!';
    if (letter >= letterSet.letterMax || letter < 0) return 0;
    if (col >= 3 || col < 0) return 0;
    if (row >= 5 || row < 0) return 0;
    return letterSet.letters[letter].rows[row].cols[col];
}

int drawString(char* string, rect_t* rect, const struct letterSet letterSet, pixel_t color, pixel_t backgroundColor) {
    static uint8_t imageBuffer[sizeof(image_t) + sizeof(pixel_t) * 5 * 3];
    static image_t* image = (image_t*) imageBuffer;
    *image = (image_t) {
        0,
        3,
        5,
        "",
        false
    };
    int charWidth = 3;
    int charHeight = 5;
    int stringLength = strlen(string);
    int charsPrinted = 0;
    for (int i = 0; i < stringLength; i++) {
        charsPrinted = i + 1;
        char c = string[i];
        int baseX = (charWidth + 1) * i;
        if (baseX + charWidth + 1 >= rect->width) {
            charsPrinted--;
            goto finish;
        }
        int baseY = (baseX / rect->width) * (charHeight + 1);
        if (baseY >= + rect->height) {
            charsPrinted--;
            goto finish;
        }
        baseX %= rect->width;
        baseX += rect->x;
        baseY += rect->y;
        for (int y = 0; y < charHeight; y++) {
            for (int x = 0; x < charWidth; x++) {
                bool draw = getLetterPixel(letterSet, c, y, x);
                pixel_t thisColor = color;
                if (!draw) thisColor = backgroundColor;
                thisColor.a = 255;
                image->pixels[y * charWidth + x] = thisColor;
            }
        }
        drawImage(image, baseX, baseY, charWidth, charHeight);
    }
finish:
    int maxWidth = MIN(charsPrinted * (charWidth + 1), rect->width);
    int maxHeight;
    if (rect->width != 0) maxHeight = MAX(charHeight + 1, (charsPrinted * (charWidth + 1) / rect->width));
    else maxHeight = charHeight + 1;
    rect->width = maxWidth;
    rect->height = maxHeight;
    return charsPrinted;
}
